              ))}
            </div>
          </motion.div>
        )}</AnimatePresence>

        <AnimatePresence>{mobile && drawer && (
          <motion.div initial={reduce ? { opacity: 0 } : { opacity: 0, height: 0 }} animate={{ opacity: 1, height: "auto" }} exit={reduce ? { opacity: 0 } : { opacity: 0, height: 0 }} style={{ overflow: "hidden", borderTop: "1px solid " + line }}>
            <div style={{ padding: twoCol ? "16px 24px" : "12px 16px 18px", maxHeight: "70vh", overflowY: "auto" }}>
              {columns.map((col) => (
                <div key={col.title} style={{ marginBottom: 20 }}><p style={{ margin: "0 0 12px", fontSize: 13, fontWeight: 700, color: faint, textTransform: "uppercase", letterSpacing: "0.04em" }}>{col.title}</p><div style={{ display: "grid", gridTemplateColumns: twoCol ? "1fr 1fr" : "1fr", gap: 12 }}>{col.links.map(rowLink)}</div></div>
              ))}
              <div style={{ borderTop: "1px solid " + line, paddingTop: 14, display: "grid", gap: 12 }}>{links.map((l) => <a key={l} href="#" style={{ ...linkStyle, fontSize: 15.5 }}>{l}</a>)}<button type="button" style={{ marginTop: 2, background: a, color: "#fff", border: 0, borderRadius: 10, padding: "13px 0", fontWeight: 700, fontSize: 15, cursor: "pointer" }}>{cta}</button></div>
            </div>
          </motion.div>
        )}</AnimatePresence>
      </div>
      <div style={{ height: "60vh" }} aria-hidden />
    </section>
  );
}

